"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([[1269],{2110:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Introduction","href":"/dev-book/","docId":"intro","unlisted":false},{"type":"category","label":"Key Concepts","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"App","href":"/dev-book/key-concepts/apps","docId":"key-concepts/apps","unlisted":false},{"type":"link","label":"Member","href":"/dev-book/key-concepts/members","docId":"key-concepts/members","unlisted":false},{"type":"link","label":"Transcoding Profile","href":"/dev-book/key-concepts/transcoding-profiles","docId":"key-concepts/transcoding-profiles","unlisted":false},{"type":"link","label":"Video Post","href":"/dev-book/key-concepts/video-posts","docId":"key-concepts/video-posts","unlisted":false},{"type":"link","label":"Video Room","href":"/dev-book/key-concepts/video-rooms","docId":"key-concepts/video-rooms","unlisted":false}],"href":"/dev-book/category/key-concepts"},{"type":"category","label":"API Documentation","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"FlipFlop App Server API","href":"/dev-book/api-documentation/flipflop-app-server-side-api","docId":"api-documentation/flipflop-app-server-side-api","unlisted":false},{"type":"link","label":"FlipFlop App Client API","href":"/dev-book/api-documentation/flipflop-app-client-side-api","docId":"api-documentation/flipflop-app-client-side-api","unlisted":false}],"href":"/dev-book/category/api-documentation"},{"type":"category","label":"SDK Documentation","collapsible":true,"collapsed":true,"items":[{"type":"category","label":"Android SDK","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Quick Start","href":"/dev-book/sdk-documentation/android-sdk/quick-start","docId":"sdk-documentation/android-sdk/quick-start","unlisted":false},{"type":"link","label":"Tutorial","href":"/dev-book/sdk-documentation/android-sdk/tutorial","docId":"sdk-documentation/android-sdk/tutorial","unlisted":false},{"type":"link","label":"Core Concepts","href":"/dev-book/sdk-documentation/android-sdk/core-concepts","docId":"sdk-documentation/android-sdk/core-concepts","unlisted":false}],"href":"/dev-book/category/android-sdk"},{"type":"category","label":"iOS SDK","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Quick Start","href":"/dev-book/sdk-documentation/ios-sdk.md/quick-start","docId":"sdk-documentation/ios-sdk.md/quick-start","unlisted":false},{"type":"link","label":"Tutorial","href":"/dev-book/sdk-documentation/ios-sdk.md/tutorial","docId":"sdk-documentation/ios-sdk.md/tutorial","unlisted":false},{"type":"link","label":"Core Concepts","href":"/dev-book/sdk-documentation/ios-sdk.md/core-concepts","docId":"sdk-documentation/ios-sdk.md/core-concepts","unlisted":false}],"href":"/dev-book/category/ios-sdk"}],"href":"/dev-book/category/sdk-documentation"}]},"docs":{"api-documentation/flipflop-app-client-side-api":{"id":"api-documentation/flipflop-app-client-side-api","title":"FlipFlop App Client API","description":"The FlipFlop App Client API is designed to allow the client to directly call the FlipFlop App API when all features of FlipFlop Cloud need to be accessed through the backend of a service. This can help reduce the workload on the backend and avoid delays caused by relaying requests through it.","sidebar":"tutorialSidebar"},"api-documentation/flipflop-app-server-side-api":{"id":"api-documentation/flipflop-app-server-side-api","title":"FlipFlop App Server API","description":"The FlipFlop App Server API is used when the backend server needs to handle user requests on behalf of the user or when it is necessary to operate services according to business logic using FlipFlop Cloud features.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Introduction","description":"Overview and Features of FlipFlop Cloud Service","sidebar":"tutorialSidebar"},"key-concepts/apps":{"id":"key-concepts/apps","title":"App","description":"A FlipFlop Cloud App is an abstract concept corresponding to a service that either intends to implement video-related features or wishes to utilize these features even without having a concrete service entity. Through an App, FlipFlop Cloud separates video-related functionalities for each service, allowing the platform to manage information and provide features independently. FlipFlop Cloud offers various types of apps, allowing users to select the most suitable one based on how and in what environment they intend to use video features.","sidebar":"tutorialSidebar"},"key-concepts/members":{"id":"key-concepts/members","title":"Member","description":"A member refers to a user belonging to an app in FlipFlop Cloud. All video-related features in FlipFlop Cloud are designed to be used through members. Therefore, if you want to provide video features to users of a concrete service via FlipFlop Cloud, you need to register the users of your service as members within the App. The minimum required information for registration is the user ID from the actual service. Once a member is registered to an App, their actual service ID is stored and managed as a string attribute called appUserId. Although an internal, separate ID is generated, all member activities are designed to be tracked based on appUserId for the convenience of developers using FlipFlop Cloud.","sidebar":"tutorialSidebar"},"key-concepts/transcoding-profiles":{"id":"key-concepts/transcoding-profiles","title":"Transcoding Profile","description":"Usage of Transcoding Profiles","sidebar":"tutorialSidebar"},"key-concepts/video-posts":{"id":"key-concepts/video-posts","title":"Video Post","description":"A Video Post is a unit used to manage videos in the form of posts, allowing users to share video content. When viewing shared videos, they need to be viewed in a compressed format to save network bandwidth, which requires a transcoding process. Therefore, even if the purpose is not to share the video but rather to transcode it, a Video Post should be used.","sidebar":"tutorialSidebar"},"key-concepts/video-rooms":{"id":"key-concepts/video-rooms","title":"Video Room","description":"A Video Room allows people to communicate and interact in real-time using video as a medium. Currently, FlipFlop Cloud supports the following two types of Video Rooms, with more types planned for the future:","sidebar":"tutorialSidebar"},"sdk-documentation/android-sdk/core-concepts":{"id":"sdk-documentation/android-sdk/core-concepts","title":"Core Concepts","description":"Connecting to Server","sidebar":"tutorialSidebar"},"sdk-documentation/android-sdk/quick-start":{"id":"sdk-documentation/android-sdk/quick-start","title":"Quick Start","description":"1. Prerequisites","sidebar":"tutorialSidebar"},"sdk-documentation/android-sdk/tutorial":{"id":"sdk-documentation/android-sdk/tutorial","title":"Tutorial","description":"1. Prerequisites","sidebar":"tutorialSidebar"},"sdk-documentation/ios-sdk.md/core-concepts":{"id":"sdk-documentation/ios-sdk.md/core-concepts","title":"Core Concepts","description":"Connecting to Server","sidebar":"tutorialSidebar"},"sdk-documentation/ios-sdk.md/quick-start":{"id":"sdk-documentation/ios-sdk.md/quick-start","title":"Quick Start","description":"1. Prerequisites","sidebar":"tutorialSidebar"},"sdk-documentation/ios-sdk.md/tutorial":{"id":"sdk-documentation/ios-sdk.md/tutorial","title":"Tutorial","description":"1. Prerequisites","sidebar":"tutorialSidebar"}}}}')}}]);